class Solution:
    def checkPowersOfThree(self, n):
        powers = []
        p = 1
        while p <= n:
            powers.append(p)
            p *= 3
        for mask in range(1 << len(powers)):
            s = 0
            for i in range(len(powers)):
                if mask & (1 << i):
                    s += powers[i]
            if s == n:
                return True
        return False

